      true,                    
      'fa-brands fa-whatsapp',
      now()
    );
  END IF;

  RETURN NEW;
EXCEPTION
  WHEN OTHERS THEN
    -- BLINDAGEM: Se der qualquer erro na notificação, IGNORA e deixa a mensagem entrar
    RAISE WARNING 'Erro ao criar notificação ignorado para salvar mensagem: %', SQLERRM;
    RETURN NEW;
END;

